dtsPropsFor.Button:
/** Visual style variant. @default 'default' */
variant?: 'default' | 'destructive' | 'outline' | 'secondary' | 'ghost' | 'link';
/** Size preset. @default 'default' */
size?: 'default' | 'wide' | 'sm' | 'lg' | 'pill' | 'icon';
/** Render as the child element via Radix Slot instead of a native <button>. @default false */
asChild?: boolean;
children?: React.ReactNode;
className?: string;
disabled?: boolean;
type?: 'button' | 'submit' | 'reset';
onClick?: React.MouseEventHandler<HTMLButtonElement>;
/** Plus all native <button> attributes. */
[key: string]: unknown;

dtsPropsFor.Checkbox:
/** Controlled checked state; 'indeterminate' for a mixed state. */
checked?: boolean | 'indeterminate';
/** Uncontrolled initial checked state. */
defaultChecked?: boolean;
onCheckedChange?: (checked: boolean | 'indeterminate') => void;
disabled?: boolean;
required?: boolean;
name?: string;
value?: string;
id?: string;
className?: string;

dtsPropsFor.Input:
type?: React.HTMLInputTypeAttribute;
placeholder?: string;
value?: string;
defaultValue?: string;
disabled?: boolean;
required?: boolean;
readOnly?: boolean;
name?: string;
id?: string;
className?: string;
onChange?: React.ChangeEventHandler<HTMLInputElement>;
/** Apply the invalid styling (red border). */
'aria-invalid'?: boolean | 'true' | 'false';
/** Plus all native <input> attributes. */
[key: string]: unknown;

dtsPropsFor.Label:
/** Associates the label with a form control by its id. */
htmlFor?: string;
children?: React.ReactNode;
className?: string;
/** Plus all native <label> attributes. */
[key: string]: unknown;

dtsPropsFor.StatusButton:
/** Drives the trailing status indicator: spinner / check / cross. */
status: 'idle' | 'pending' | 'success' | 'error';
/** Optional tooltip message shown on the status indicator. */
message?: string | null;
/** Tuning for the pending-spinner delay (see the `spin-delay` package). */
spinDelay?: { delay?: number; minDuration?: number };
/** Inherited from Button. @default 'default' */
variant?: 'default' | 'destructive' | 'outline' | 'secondary' | 'ghost' | 'link';
/** Inherited from Button. @default 'default' */
size?: 'default' | 'wide' | 'sm' | 'lg' | 'pill' | 'icon';
children?: React.ReactNode;
className?: string;
disabled?: boolean;
type?: 'button' | 'submit' | 'reset';
onClick?: React.MouseEventHandler<HTMLButtonElement>;
/** Plus all native <button> attributes. */
[key: string]: unknown;

dtsPropsFor.Textarea:
placeholder?: string;
value?: string;
defaultValue?: string;
rows?: number;
disabled?: boolean;
required?: boolean;
readOnly?: boolean;
name?: string;
id?: string;
className?: string;
onChange?: React.ChangeEventHandler<HTMLTextAreaElement>;
/** Plus all native <textarea> attributes. */
[key: string]: unknown;

dtsPropsFor.DropdownMenu:
/** Compound (Radix) menu. Compose: DropdownMenuTrigger + DropdownMenuContent containing DropdownMenuLabel / DropdownMenuSeparator / DropdownMenuItem / DropdownMenuCheckboxItem / DropdownMenuRadioGroup+DropdownMenuRadioItem / DropdownMenuSub(+SubTrigger/+SubContent) / DropdownMenuShortcut. */
/** Controlled open state. */
open?: boolean;
/** Uncontrolled initial open state. */
defaultOpen?: boolean;
onOpenChange?: (open: boolean) => void;
/** Block outside interaction while open. @default true */
modal?: boolean;
dir?: 'ltr' | 'rtl';
children?: React.ReactNode;

dtsPropsFor.InputOTP:
/** One-time-code input (the `input-otp` package). Compose the boxes with InputOTPGroup + InputOTPSlot (index 0..maxLength-1), optionally split by InputOTPSeparator. */
/** Number of character slots. */
maxLength: number;
value?: string;
defaultValue?: string;
onChange?: (value: string) => void;
onComplete?: (value: string) => void;
disabled?: boolean;
/** Regex source constraining allowed characters. */
pattern?: string;
className?: string;
containerClassName?: string;
children?: React.ReactNode;

dtsPropsFor.Tooltip:
/** Compound (Radix) tooltip. Compose: TooltipTrigger (use asChild to wrap your own control) + TooltipContent. A TooltipProvider is applied automatically by the wrapper. */
/** Controlled open state. */
open?: boolean;
defaultOpen?: boolean;
onOpenChange?: (open: boolean) => void;
/** Hover delay (ms) before opening. */
delayDuration?: number;
children?: React.ReactNode;

dtsPropsFor.Accordion:
/** Compound (Radix) disclosure. Compose: Accordion (root) wrapping one or more AccordionItem (each with a unique `value`), and inside each item an AccordionTrigger + AccordionContent. Styled with design tokens only; the open trigger brand-tints and its plus icon rotates 45°. */
/** Open behavior. @default 'single' (collapsible) */
type?: 'single' | 'multiple';
/** Controlled open value(s) — a string for single, string[] for multiple. */
value?: string | string[];
/** Uncontrolled initial open value(s). */
defaultValue?: string | string[];
onValueChange?: (value: string | string[]) => void;
/** Single-only: allow closing the open item by clicking it again. @default true */
collapsible?: boolean;
dir?: 'ltr' | 'rtl';
orientation?: 'horizontal' | 'vertical';
children?: React.ReactNode;
className?: string;

dtsPropsFor.Slider:
/** Single-thumb slider on the Radix base (keyboard + ARIA for free). Presents a friendly single-number API over Radix's array form. */
/** Controlled single value. */
value?: number;
/** Uncontrolled initial value. */
defaultValue?: number;
/** Fires with the new single value as the thumb moves. */
onChange?: (value: number) => void;
min?: number;
max?: number;
step?: number;
disabled?: boolean;
/** CSS background painted on the track (e.g. an oklch hue / chroma / light sweep); when set, the filled range goes transparent so the gradient reads as the whole track. */
trackGradient?: string;
/** Accessible label forwarded to the thumb (the element with `slider` role). */
'aria-label'?: string;
'aria-labelledby'?: string;
className?: string;

dtsPropsFor.CommandPalette:
/** Self-contained ⌘K command palette. Pass a `commands` registry and it renders the searchable, grouped, keyboard-navigable list. Omit `open` to render inline (a bordered card — used by the styleguide and tests); pass `open`/`onOpenChange` to render as a focus-trapped dialog overlay. The built-in matcher owns all ranking/grouping/filtering. */
/** The registry to search. Each command is { id, title, group, keywords?, icon? } plus EITHER `href` (navigation) XOR `run` (action) — never both. */
commands: Array<{ id: string; title: string; group: string; keywords?: string[]; icon?: string; href?: string; run?: () => void }>;
/** When provided, renders as a controlled dialog overlay instead of inline. */
open?: boolean;
onOpenChange?: (open: boolean) => void;
/** Navigate for `href` commands. @default full-page assignment */
onNavigate?: (href: string) => void;
/** Suggested-action chips for the empty / no-match state (each fires its `run`). */
emptyActions?: Array<{ id: string; title: string; group: string; icon?: string; run: () => void }>;
/** @default 'Type a command or search…' */
placeholder?: string;
